#include<bits/stdc++.h>
using namespace std;
int main(){
	int cnt[1001];
	int n,ma,mi=0;
	double cn=0;
	cin>>n;
	for(int i=0;i<n;i++)
	{
		cin>>cnt[i];
	}
	ma=cnt[0];
	mi=cnt[0];
	for(int j=1;j<n;j++)
	{
		if(cnt[j]>ma)
		{
			ma=cnt[j];
		}
		cn=cn+cnt[j];
		
	}
	cn=cn+cnt[0];
	for(int k=1;k<n;k++)
	{
		if(cnt[k]<mi)
		{
			mi=cnt[k];
	    }
	}
	cn=cn-mi-ma;
	cn=cn/(n-2);
	printf("%.2f",cn);
	return 0;
}
